}

package bead

import (
	"encoding/json"
	"fmt"
	"os/exec"
	"strings"
)

// ExternalBackend delegates storage to an external tool (bd or br).
//
// bd and br today have no per-collection scoping in their CLI surface — `bd
// list --json` and `bd import` always operate on the tool's primary store.
// To preserve the bd/br interchange contract for the default "beads"
// collection AND give callers a working path for non-default collections
// (notably "beads-archive"), ExternalBackend may carry a JSONL fallback
// that handles the read/write/lock plumbing for any collection the tool
// cannot natively serve. The default collection always routes through the
// external tool; non-default collections route through the fallback when
// one is present.
type ExternalBackend struct {
	Tool       string // "bd" or "br"
	Collection string
	// fallback handles all Init/Read/Write/Lock calls when set. Populated
	// by NewExternalBackendWithFallback for non-default collections; nil
	// for the default collection so the external tool stays authoritative.
	fallback RawBackend
}

// Compile-time check: ExternalBackend satisfies RawBackend.
var _ RawBackend = (*ExternalBackend)(nil)

// NewExternalBackend creates a backend that shells out to the given tool.
func NewExternalBackend(tool, collection string) (*ExternalBackend, error) {
	if _, err := exec.LookPath(tool); err != nil {
		return nil, fmt.Errorf("bead: backend %s not found in PATH", tool)
	}
	return &ExternalBackend{Tool: tool, Collection: collection}, nil
}

// NewExternalBackendWithFallback constructs an external backend that routes
// non-default collections through the supplied fallback Backend. fallback is
// ignored for the default collection so the bd/br interchange path stays
// unchanged. fallback may be nil when the caller knows the collection is the
// default; callers handling arbitrary collections should always supply one.
func NewExternalBackendWithFallback(tool, collection string, fallback RawBackend) (*ExternalBackend, error) {
	e, err := NewExternalBackend(tool, collection)
	if err != nil {
		return nil, err
	}
	if collection != DefaultCollection {
		e.fallback = fallback
	}
	return e, nil
}

// Init is a no-op for external backends — they manage their own storage.
// The fallback (when set) initializes its JSONL file and lock dir on demand.
func (e *ExternalBackend) Init() error {
	if e.fallback != nil {
		return e.fallback.Init()
	}
	return nil
}

// ReadAll lists all beads from the external tool.
func (e *ExternalBackend) ReadAll() ([]Bead, error) {
	if e.fallback != nil {
		return e.fallback.ReadAll()
	}
	cmd := exec.Command(e.Tool, "list", "--json")
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("bead: %s list --json: %w", e.Tool, err)
	}

	trimmed := strings.TrimSpace(string(output))
	if trimmed == "" || trimmed == "[]" {
		return nil, nil
	}

	// Try JSON array first
	if strings.HasPrefix(trimmed, "[") {
		var raw []json.RawMessage
		if err := json.Unmarshal([]byte(trimmed), &raw); err != nil {
			return nil, fmt.Errorf("bead: %s parse: %w", e.Tool, err)
		}
		var beads []Bead
		for _, r := range raw {
			b, err := unmarshalBead(r)
			if err != nil {
				continue
			}
			beads = append(beads, b)
		}
		return beads, nil
	}

	// JSONL fallback
	var beads []Bead
	for _, line := range strings.Split(trimmed, "\n") {
		line = strings.TrimSpace(line)
		if line == "" {
			continue
		}
		b, err := unmarshalBead([]byte(line))
		if err != nil {
			continue
		}
		beads = append(beads, b)
	}
	return beads, nil
}

// WriteAll writes all beads back via the external tool.
// For bd/br, we export as JSONL and import. This is a full replace.
func (e *ExternalBackend) WriteAll(beads []Bead) error {
	if e.fallback != nil {
		return e.fallback.WriteAll(beads)
	}
	// Build JSONL
	var sb strings.Builder
	for _, b := range beads {
		data, err := marshalBead(b)
		if err != nil {
			return fmt.Errorf("bead: marshal for %s: %w", e.Tool, err)
		}
		sb.Write(data)
		sb.WriteByte('\n')
	}

	// Pipe to tool's import command
	cmd := exec.Command(e.Tool, "import", "--from", "jsonl", "--replace", "-")
	cmd.Stdin = strings.NewReader(sb.String())
	if output, err := cmd.CombinedOutput(); err != nil {
		return fmt.Errorf("bead: %s import: %s: %w", e.Tool, string(output), err)
	}
	return nil
}

// WithLock for external backends is a no-op — the tool handles its own
// locking. When a JSONL fallback is in play we delegate locking to it so
// concurrent writers serialize on the fallback file's lock dir.
func (e *ExternalBackend) WithLock(fn func() error) error {
	if e.fallback != nil {
		return e.fallback.WithLock(fn)
	}
	return fn()
}

package bead

import (
	"fmt"
	"os"
	"sort"
	"time"
)

// JSONLBackend stores beads as newline-delimited JSON in a single file under
// a .ddx directory. It is the storage shape used by Store's built-in path and
// is also the fallback ExternalBackend reaches for when bd/br cannot serve a
// non-default collection (e.g. "beads-archive"). Constructed directly only
// when a RawBackend value is needed standalone — Store's inline path predates
// this type and continues to operate on the same file format.
type JSONLBackend struct {
	Dir      string
	File     string
	LockDir  string
	LockWait time.Duration
}

// NewJSONLBackend constructs a JSONL-backed Backend rooted at dir. file and
// lockDir must be absolute (or rooted under dir) and are written/locked
// directly. lockWait bounds how long WithLock spins before giving up.
// Compile-time check: JSONLBackend satisfies RawBackend.
var _ RawBackend = (*JSONLBackend)(nil)

func NewJSONLBackend(dir, file, lockDir string, lockWait time.Duration) *JSONLBackend {
	return &JSONLBackend{Dir: dir, File: file, LockDir: lockDir, LockWait: lockWait}
}

func (j *JSONLBackend) Init() error {
	if err := os.MkdirAll(j.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: init dir: %w", err)
	}
	f, err := os.OpenFile(j.File, os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("bead: init file: %w", err)
	}
	return f.Close()
}

func (j *JSONLBackend) ReadAll() ([]Bead, error) {
	data, err := os.ReadFile(j.File)
	if os.IsNotExist(err) {
		return nil, nil
	}
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", j.File, err)
	}
	beads, _, err := parseBeadJSONL(data)
	if err != nil {
		return nil, fmt.Errorf("bead: parse %s: %w", j.File, err)
	}
	return foldLatestBeads(beads), nil
}

func (j *JSONLBackend) WriteAll(beads []Bead) error {
	sort.Slice(beads, func(a, b int) bool { return beads[a].ID < beads[b].ID })
	if err := os.MkdirAll(j.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: mkdir: %w", err)
	}
	var buf []byte
	for _, b := range beads {
		data, err := marshalBead(b)
		if err != nil {
			return fmt.Errorf("bead: marshal: %w", err)
		}
		buf = append(buf, data...)
		buf = append(buf, '\n')
	}
	return writeAtomicFile(j.File, buf)
}

func (j *JSONLBackend) WithLock(fn func() error) error {
	wait := j.LockWait
	if wait <= 0 {
		wait = 10 * time.Second
	}
	if err := acquireDirLock(j.Dir, j.LockDir, wait); err != nil {
		return err
	}
	defer os.RemoveAll(j.LockDir)
	return fn()
}

	return &cp
}

func mustJSON(v any) json.RawMessage {
	if v == nil {
		return nil
	}
	data, err := json.Marshal(v)
	if err != nil {
		return nil
	}
	return data
}

// SubscribeChangeEvents streams change events for the given project ID.
func (c *Client) SubscribeChangeEvents(ctx context.Context, projectID string) (<-chan ChangeEvent, error) {
	sub, ok := c.transport.(SubscriptionTransport)
	if !ok {
		return nil, fmt.Errorf("axon: subscription transport not configured")
	}

	raw, err := sub.Subscribe(ctx, changeEventsSubscription, map[string]any{"projectID": projectID})
	if err != nil {
		return nil, err
	}

	out := make(chan ChangeEvent)
	go func() {
		defer close(out)
		for payload := range raw {
			var env changeEventsEnvelope
			if err := json.Unmarshal(payload, &env); err != nil {
				continue
			}
			if env.Data.ChangeEvents == nil {
				continue
			}
			select {
			case out <- *env.Data.ChangeEvents:
			case <-ctx.Done():
				return
			}
		}
	}()

	return out, nil
}

package axon

import (
	"context"
	"encoding/json"
	"fmt"
	"net/http"
	"strings"
	"sync"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/gorilla/websocket"
)

const graphqlWSSubprotocol = "graphql-transport-ws"

const changeEventsSubscription = `subscription ChangeEvents($projectID: ID!) { changeEvents(projectID: $projectID) { ...ChangeEventFields } }`

// ChangeEvent mirrors the GraphQL subscription payload for lifecycle updates.
type ChangeEvent struct {
	EventID   string    `json:"eventID"`
	BeadID    string    `json:"beadID"`
	Kind      string    `json:"kind"`
	Summary   string    `json:"summary"`
	Body      string    `json:"body"`
	Actor     string    `json:"actor"`
	Timestamp time.Time `json:"timestamp"`
}

// ChangeEventFromLifecycle converts the local bead lifecycle event into the
// Axon GraphQL subscription shape.
func ChangeEventFromLifecycle(src bead.LifecycleEvent) ChangeEvent {
	return ChangeEvent{
		EventID:   src.EventID,
		BeadID:    src.BeadID,
		Kind:      src.Kind,
		Summary:   src.Summary,
		Body:      src.Body,
		Actor:     src.Actor,
		Timestamp: src.Timestamp,
	}
}

// ToLifecycleEvent converts the GraphQL subscription payload back into the
// local bead lifecycle model.
func (c ChangeEvent) ToLifecycleEvent() bead.LifecycleEvent {
	return bead.LifecycleEvent{
		EventID:   c.EventID,
		BeadID:    c.BeadID,
		Kind:      c.Kind,
		Summary:   c.Summary,
		Body:      c.Body,
		Actor:     c.Actor,
		Timestamp: c.Timestamp,
	}
}

// SubscriptionTransport is the minimal GraphQL-over-WebSocket transport used
// by the Axon client subscription path.
type SubscriptionTransport interface {
	Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error)
}

// DualTransport lets callers combine a query transport and a subscription
// transport behind the same Client value.
type DualTransport struct {
	Queries       Transport
	Subscriptions SubscriptionTransport
}

// Query forwards GraphQL queries and mutations to the query transport.
func (d DualTransport) Query(ctx context.Context, query string, variables map[string]any, response any) error {
	if d.Queries == nil {
		return fmt.Errorf("axon: query transport not configured")
	}
	return d.Queries.Query(ctx, query, variables, response)
}

// Subscribe forwards GraphQL subscriptions to the subscription transport.
func (d DualTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
	if d.Subscriptions == nil {
		return nil, fmt.Errorf("axon: subscription transport not configured")
	}
	return d.Subscriptions.Subscribe(ctx, query, variables)
}

// WebSocketSubscriptionTransport speaks the graphql-transport-ws protocol.
type WebSocketSubscriptionTransport struct {
	URL         string
	Header      http.Header
	Dialer      *websocket.Dialer
	InitPayload map[string]any
}

// NewWebSocketSubscriptionTransport creates a websocket subscription transport
// rooted at url. The URL may be ws://, wss://, http://, or https://.
func NewWebSocketSubscriptionTransport(url string) *WebSocketSubscriptionTransport {
	return &WebSocketSubscriptionTransport{URL: url}
}

// Query is unsupported on the websocket subscription transport.
func (t *WebSocketSubscriptionTransport) Query(context.Context, string, map[string]any, any) error {
	return fmt.Errorf("axon: websocket subscription transport does not execute queries")
}

// Subscribe opens a GraphQL WebSocket subscription and streams raw payloads
// from graphql-transport-ws next messages.
func (t *WebSocketSubscriptionTransport) Subscribe(ctx context.Context, query string, variables map[string]any) (<-chan json.RawMessage, error) {
	url := normalizeWebSocketURL(strings.TrimSpace(t.URL))
	if url == "" {
		return nil, fmt.Errorf("axon: websocket subscription url is required")
	}

	dialer := websocket.DefaultDialer
	if t.Dialer != nil {
		dialer = t.Dialer
	}
	if len(dialer.Subprotocols) == 0 {
		dialer = cloneDialer(dialer)
		dialer.Subprotocols = []string{graphqlWSSubprotocol}
	}

	header := cloneHeader(t.Header)
	conn, _, err := dialer.DialContext(ctx, url, header)
	if err != nil {
		return nil, fmt.Errorf("axon: websocket dial: %w", err)
	}

	closed := make(chan struct{})
	var closeOnce sync.Once
	cleanup := func() {
		closeOnce.Do(func() {
			close(closed)
			_ = conn.Close()
		})
	}
	go func() {
		select {
		case <-ctx.Done():
			cleanup()
		case <-closed:
		}
	}()

	if conn.Subprotocol() != "" && conn.Subprotocol() != graphqlWSSubprotocol {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subprotocol mismatch: got %q want %q", conn.Subprotocol(), graphqlWSSubprotocol)
	}

	if err := conn.WriteJSON(graphqlWSMessage{Type: "connection_init", Payload: mustJSON(t.InitPayload)}); err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket connection_init: %w", err)
	}

	for {
		var msg graphqlWSMessage
		if err := conn.ReadJSON(&msg); err != nil {
			cleanup()
			return nil, fmt.Errorf("axon: websocket ack: %w", err)
		}
		switch msg.Type {
		case "connection_ack":
			goto subscribed
		case "ping":
			_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
		case "error":
			cleanup()
			return nil, fmt.Errorf("axon: websocket connection error")
		}
	}

subscribed:
	subPayload, err := json.Marshal(map[string]any{
		"query":     query,
		"variables": variables,
	})
	if err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subscribe payload: %w", err)
	}
	if err := conn.WriteJSON(graphqlWSMessage{ID: "1", Type: "subscribe", Payload: subPayload}); err != nil {
		cleanup()
		return nil, fmt.Errorf("axon: websocket subscribe: %w", err)
	}

	out := make(chan json.RawMessage)
	go func() {
		defer close(out)
		defer cleanup()
		for {
			var msg graphqlWSMessage
			if err := conn.ReadJSON(&msg); err != nil {
				return
			}
			switch msg.Type {
			case "next":
				if len(msg.Payload) == 0 {
					continue
				}
				payload := append(json.RawMessage(nil), msg.Payload...)
				select {
				case out <- payload:
				case <-ctx.Done():
					return
				}
			case "complete":
				return
			case "ping":
				_ = conn.WriteJSON(graphqlWSMessage{Type: "pong"})
			case "error":
				return
			}
		}
	}()

	return out, nil
}

